<template>
  <LayoutPage class="show-viewport">
    <div class="viewport">
      <div class="viewport__main">
        <div class="title">your viewport size is :</div>
        <div class="document-size"></div>
      </div>
      <div class="viewport__other">
        <div class="browser">
          <div class="browser__title">Browser : </div>
          <div class="browser__ctr"></div>
        </div>

        <div class="dpr">
          <div class="dpr__title">DPR : </div>
          <div class="dpr__number"></div>
        </div>

        <div class="screen">
          <div class="screen__title">Screen Size : </div>
          <div class="screen__size"></div>
        </div>

      </div>
    </div>
  </LayoutPage>
</template>

<script setup>
// import Markdown from 'vue3-markdown-it';
import { defineOptions, onMounted } from 'vue'
import LayoutPage from '@/components/layout/page'

defineOptions({ name: 'WhatIsMyViewport' })

// const msg = ref('404 This page could not be found.')

onMounted(() => {
  (function () {
    "use strict";

    function uaMatch(ua) {
      if (ua === undefined) {
        ua = window.navigator.userAgent;
      }
      ua = ua.toLowerCase();
      var match = /(edge)\/([\w.]+)/.exec(ua) ||
        /(opr)[\\/]([\w.]+)/.exec(ua) ||
        /(chrome)[ \\/]([\w.]+)/.exec(ua) ||
        /(iemobile)[\\/]([\w.]+)/.exec(ua) ||
        /(version)(applewebkit)[ \\/]([\w.]+).*(safari)[ \\/]([\w.]+)/.exec(ua) ||
        /(webkit)[ \\/]([\w.]+).*(version)[ \\/]([\w.]+).*(safari)[ \\/]([\w.]+)/.exec(ua) ||
        /(webkit)[ \\/]([\w.]+)/.exec(ua) ||
        /(opera)(?:.*version|)[ \\/]([\w.]+)/.exec(ua) ||
        /(msie) ([\w.]+)/.exec(ua) ||
        ua.indexOf("trident") >= 0 && /(rv)(?::| )([\w.]+)/.exec(ua) ||
        ua.indexOf("compatible") < 0 && /(mozilla)(?:.*? rv:([\w.]+)|)/.exec(ua) ||
        [];
      var platform_match = /(ipad)/.exec(ua) ||
        /(ipod)/.exec(ua) ||
        /(windows phone)/.exec(ua) ||
        /(iphone)/.exec(ua) ||
        /(kindle)/.exec(ua) ||
        /(silk)/.exec(ua) |
        /(android)/.exec(ua) ||
        /(win)/.exec(ua) ||
        /(mac)/.exec(ua) ||
        /(linux)/.exec(ua) ||
        /(cros)/.exec(ua) ||
        /(playbook)/.exec(ua) ||
        /(bb)/.exec(ua) ||
        /(blackberry)/.exec(ua) ||
        [];
      var browser = {},
        matched = {
          browser: match[5] || match[3] || match[1] || "",
          version: match[2] || match[4] || "0",
          versionNumber: match[4] || match[2] || "0",
          platform: platform_match[0] || ""
        };
      var ie = null;
      if (matched.browser) {
        browser[matched.browser] = true;
        browser.version = matched.version;
        browser.versionNumber = parseInt(matched.versionNumber, 10);
      }
      if (matched.platform) {
        browser[matched.platform] = true;
      }
      if (browser.android || browser.bb || browser.blackberry || browser.ipad || browser.iphone ||
        browser.ipod || browser.kindle || browser.playbook || browser.silk || browser["windows phone"]) {
        browser.mobile = true;
      }
      if (browser.cros || browser.mac || browser.linux || browser.win) {
        browser.desktop = true;
      }
      if (browser.chrome || browser.opr || browser.safari) {
        browser.webkit = true;
      }
      if (browser.chrome) {
        var chrome = "Chrome"
        matched.browser = chrome
        browser[chrome] = true;
      }
      if (browser.msie) {
        ie = "IE";
        matched.browser = ie;
        browser[ie] = true;
      }
      if (browser.rv || browser.iemobile) {
        ie = "IE";
        matched.browser = ie;
        browser[ie] = true;
      }
      if (browser.edge) {
        delete browser.edge;
        var msedge = "Edge";
        matched.browser = msedge;
        browser[msedge] = true;
      }
      if (browser.safari && browser.blackberry) {
        var blackberry = "blackberry";
        matched.browser = blackberry;
        browser[blackberry] = true;
      }
      if (browser.safari && browser.playbook) {
        var playbook = "playbook";
        matched.browser = playbook;
        browser[playbook] = true;
      }
      if (browser.bb) {
        var bb = "blackberry";
        matched.browser = bb;
        browser[bb] = true;
      }
      if (browser.opr) {
        var opera = "Opera";
        matched.browser = opera;
        browser[opera] = true;
      }
      if (browser.safari && browser.android) {
        var android = "Android";
        matched.browser = android;
        browser[android] = true;
      }
      if (browser.safari && browser.kindle) {
        var kindle = "kindle";
        matched.browser = kindle;
        browser[kindle] = true;
      }
      if (browser.safari && browser.silk) {
        var silk = "silk";
        matched.browser = silk;
        browser[silk] = true;
      }
      browser.name = matched.browser;
      browser.platform = matched.platform;
      return browser;
    }
    window.Browser = uaMatch(window.navigator.userAgent);
    return window.Browser;
  })();
  (function (Browser) {
    var url = location.href
    function runWebTool() {
      let documentSizeDiv = document.querySelector('.document-size')
      let browser = document.querySelector('.browser__ctr')
      let screenSizeDiv = document.querySelector('.screen__size')
      let devDPR = document.querySelector('.dpr__number')

      function catchSize() {
        var showWidth = document.documentElement.clientWidth
        var showHeight = document.documentElement.clientHeight
        var newWidth = window.screen.width
        var newHeight = window.screen.height
        var newDPR = window.devicePixelRatio.toFixed(2);

        documentSizeDiv.innerHTML = showWidth + '<span style="opacity: .3;"> × </span>' + showHeight + '<span style="opacity: .3;"> px</span>'
        screenSizeDiv.innerHTML = newWidth + '<span style="opacity: .3;"> × </span>' + newHeight + '<span style="opacity: .3;"> px</span>'
        devDPR.innerText = newDPR
      }

      browser.innerText = Browser.name + ' ( ' + Browser.version + ' ) '


      catchSize()
      window.addEventListener('resize', catchSize)
    }
    if (url.indexOf('?') !== -1) {
      var urlArray = url.split('?')[1].split('&'),
        l = urlArray.length
      for (var i = 0; i < l; i++) {
        var obj = urlArray[i]
        obj.split('=')[0] === 'webtool' && obj.split('=')[1] === 'true' && runWebTool()
      }
    }

    runWebTool();
  })(window.Browser);

  // let info = window.Browser;    
  // console.log(info);
  // function ReSize() {
  //     var w = $(window).width();
  //     var h = $(window).height();
  //     $('body').html("<ul class='browser-develop'> \
  //         <li>" + info.name + " " + info.version + "</li> \
  //         <li>width : " + w + "</li> \
  //         <li>height : " + h + "</li> \
  //         </ul>");
  // }
  // ReSize();    

  // $(window).resize(function () {
  //     ReSize();
  // });
})

</script>

<style lang="sass" scoped>
@import @sass/init
@import @sass/helpers

@import ./style
</style>
